/* bit layout, LSB first: SURNAME 16 | GIVEN 17 | TITLE 7 | PREFIX 8 = 48/48 bits
   layer index: pro = idx >> deu_bits, deu = idx & ((1<<deu_bits)-1)
   GIVEN/SURNAME pro stems are PREFIX-FREE -> decoding is a
   deterministic prefix scan and the mapping is bijective. */

/* One entry per hostname token (PREFIX, TITLE, GIVEN, SURNAME), in
 * left-to-right token order. Field order matches the name_layer_t
 * struct in name_data.h:
 *   { pro_data, pro_offsets, pro_count,
 *     deu_data, deu_offsets, deu_count,
 *     deu_bits, bits }
 * - pro_*: the stem table for this token (word list + offsets + word count).
 * - deu_*: the ending table glued onto the stem (empty for PREFIX/TITLE,
 *   which are single whole words with no stem+ending split).
 * - deu_bits: how many low bits of the layer index select the ending
 *   (0 when there's no ending table).
 * - bits: total bits this layer consumes out of the 48-bit MAC value;
 *   the four `bits` values sum to 48 (8+7+17+16), matching the layout
 *   comment above. */
const name_layer_t NAME_LAYERS[N_LAYERS] = {
    { PREFIX_PRO_DATA, PREFIX_PRO_OFFSETS, 256, EMPTY_DATA, EMPTY_OFFSETS, 1, 0, 8 },
    { TITLE_PRO_DATA, TITLE_PRO_OFFSETS, 128, EMPTY_DATA, EMPTY_OFFSETS, 1, 0, 7 },
    { GIVEN_PRO_DATA, GIVEN_PRO_OFFSETS, 256, GIVEN_DEU_DATA, GIVEN_DEU_OFFSETS, 512, 9, 17 },
    { SURNAME_PRO_DATA, SURNAME_PRO_OFFSETS, 256, SURNAME_DEU_DATA, SURNAME_DEU_OFFSETS, 256, 8, 16 }
};

/* Round keys for the 4-round Feistel permutation in mac_hostname.c.
 * This is what actually scrambles the MAC value before it's split
 * into the four layer indexes above - without it, similar MACs (e.g.
 * from the same device batch) would produce suspiciously similar
 * hostnames. The permutation is reversible, so a hostname always maps
 * back to exactly the original MAC. These are fixed constants, not
 * secrets - anyone with this source can decode any hostname. */
const uint32_t ROUND_KEYS[N_ROUNDS] = { 0x9E37D5, 0xC90FDB, 0xADF85B, 0x6A09E7 };
